import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("FileLogger")
struct FileLoggerTests {
    private func makeTempPath() -> String {
        NSTemporaryDirectory() + "ai-tracker-log-\(UUID().uuidString)/test.log"
    }

    @Test("creates directory and log file on first write")
    func createsFile() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.info, "hello")
        #expect(FileManager.default.fileExists(atPath: path))
    }

    @Test("respects minimum log level")
    func respectsMinLevel() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .warning)
        logger.log(.debug, "should not appear")
        logger.log(.info, "should not appear")
        logger.log(.warning, "should appear")
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(!content.contains("should not appear"))
        #expect(content.contains("should appear"))
    }

    @Test("log entry format contains timestamp and level")
    func logFormat() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.error, "test message")
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(content.contains("[ERROR]"))
        #expect(content.contains("test message"))
        #expect(content.contains("[20")) // ISO8601 year prefix
    }

    @Test("LogLevel.from parses strings correctly")
    func logLevelFromString() {
        #expect(LogLevel.from(string: "debug") == .debug)
        #expect(LogLevel.from(string: "DEBUG") == .debug)
        #expect(LogLevel.from(string: "warning") == .warning)
        #expect(LogLevel.from(string: "warn") == .warning)
        #expect(LogLevel.from(string: "error") == .error)
        #expect(LogLevel.from(string: "info") == .info)
        #expect(LogLevel.from(string: "garbage") == .info)
    }

    @Test("LogLevel comparison works")
    func logLevelComparison() {
        #expect(LogLevel.debug < LogLevel.info)
        #expect(LogLevel.info < LogLevel.warning)
        #expect(LogLevel.warning < LogLevel.error)
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("UsagesFileManager")
struct UsagesFileManagerTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-tests-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private func makeManager(dir: String) -> UsagesFileManager {
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        return UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
    }

    @Test("read returns empty file when no file exists")
    func readMissing() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let result = mgr.read()
        #expect(result.usages.isEmpty)
    }

    @Test("update creates file and writes entries")
    func updateCreatesFile() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let entry = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T15:00:00+00:00",
                        windowDurationMinutes: 300, usagePercent: 50),
        ])
        mgr.update(with: [entry])

        let result = mgr.read()
        #expect(result.usages.count == 1)
        #expect(result.usages[0].vendor == "claude")
        #expect(result.usages[0].account == "a@b.com")
    }

    @Test("update merges by (vendor, account) — upserts existing")
    func updateUpserts() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)

        let v1 = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T15:00:00+00:00",
                        windowDurationMinutes: 300, usagePercent: 30),
        ])
        mgr.update(with: [v1])

        let v2 = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T20:00:00+00:00",
                        windowDurationMinutes: 300, usagePercent: 70),
        ])
        mgr.update(with: [v2])

        let result = mgr.read()
        #expect(result.usages.count == 1)
        #expect(result.usages[0].metrics == v2.metrics)
    }

    @Test("update appends new vendor without removing existing")
    func updateAppendsNewVendor() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)

        mgr.update(with: [VendorUsageEntry(vendor: "claude", account: "a@b.com")])
        mgr.update(with: [VendorUsageEntry(vendor: "codex", account: "c@d.com")])

        let result = mgr.read()
        #expect(result.usages.count == 2)
        #expect(result.usages.contains(where: { $0.vendor == "claude" }))
        #expect(result.usages.contains(where: { $0.vendor == "codex" }))
    }

    @Test("merge logic — same vendor different account appends")
    func mergeDifferentAccounts() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        let existing = UsagesFile(usages: [
            VendorUsageEntry(vendor: "claude", account: "a@b.com"),
        ])
        let incoming = [VendorUsageEntry(vendor: "claude", account: "other@b.com")]
        let merged = mgr.merge(existing: existing, incoming: incoming)
        #expect(merged.usages.count == 2)
    }

    @Test("read handles corrupt JSON gracefully")
    func readCorruptJSON() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        try! "not json".write(toFile: mgr.filePath, atomically: true, encoding: .utf8)
        let result = mgr.read()
        #expect(result.usages.isEmpty)
    }

    @Test("JSON output is pretty-printed and human-readable")
    func jsonIsPrettyPrinted() {
        let dir = makeTempDir()
        let mgr = makeManager(dir: dir)
        mgr.update(with: [VendorUsageEntry(vendor: "claude", account: "a@b.com")])
        let raw = try! String(contentsOfFile: mgr.filePath, encoding: .utf8)
        #expect(raw.contains("\n"))
        #expect(raw.contains("\"vendor\""))
    }
}

import Foundation

public actor ClaudeCodeConnector: UsageConnector {
    nonisolated public let vendor = "claude"

    private let claudeConfigPath: String
    private let logger: FileLogger
    private let session: URLSession
    private let keychainServiceName: String

    public init(
        claudeConfigPath: String? = nil,
        logger: FileLogger = Loggers.claude,
        session: URLSession = .shared,
        keychainServiceName: String = "Claude Code-credentials"
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.claudeConfigPath = claudeConfigPath ?? "\(home)/.claude.json"
        self.logger = logger
        self.session = session
        self.keychainServiceName = keychainServiceName
    }

    // MARK: - UsageConnector

    nonisolated public func resolveActiveAccount() -> String? {
        guard let data = FileManager.default.contents(atPath: claudeConfigPath) else {
            logger.log(.warning, "Cannot read \(claudeConfigPath)")
            return nil
        }
        do {
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let oauth = json?["oauthAccount"] as? [String: Any]
            return oauth?["emailAddress"] as? String
        } catch {
            logger.log(.error, "Failed to parse \(claudeConfigPath): \(error)")
            return nil
        }
    }

    public func fetchUsages() async throws -> [VendorUsageEntry] {
        let account = resolveActiveAccount() ?? "unknown"
        logger.log(.info, "Fetching usages for account=\(account)")

        let token: String
        do {
            token = try fetchOAuthToken()
        } catch {
            logger.log(.error, "Token retrieval failed: \(error)")
            return [errorEntry(account: account, type: "token_error")]
        }

        guard let url = URL(string: "https://api.anthropic.com/api/oauth/usage") else {
            return [errorEntry(account: account, type: "api_error")]
        }
        var request = URLRequest(url: url)
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        // Required by the OAuth usage endpoint — beta flag must match the rollout date
        request.setValue("oauth-2025-04-20", forHTTPHeaderField: "anthropic-beta")
        request.timeoutInterval = 5

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            logger.log(.error, "API request failed: \(error)")
            return [errorEntry(account: account, type: "api_error")]
        }

        guard let http = response as? HTTPURLResponse, http.statusCode == 200 else {
            let code = (response as? HTTPURLResponse)?.statusCode ?? -1
            logger.log(.error, "API returned HTTP \(code)")
            return [errorEntry(account: account, type: "http_\(code)")]
        }

        do {
            let usage = try parseAPIResponse(data)
            let now = ISO8601DateFormatter().string(from: Date())
            logger.log(.info, "Fetched successfully: session=\(usage.sessionPercent)% weekly=\(usage.weeklyPercent)%")
            return [VendorUsageEntry(
                vendor: vendor,
                account: account,
                isActive: true,
                lastAcquiredOn: now,
                lastError: nil,
                metrics: [
                    // Window durations are not in the API response — they're fixed by Claude's rate-limit policy
                    .timeWindow(
                        name: "session",
                        resetAt: usage.sessionResetAt,
                        windowDurationMinutes: 300,  // 5 hours
                        usagePercent: usage.sessionPercent
                    ),
                    .timeWindow(
                        name: "weekly",
                        resetAt: usage.weeklyResetAt,
                        windowDurationMinutes: 10080,  // 7 days
                        usagePercent: usage.weeklyPercent
                    ),
                ]
            )]
        } catch {
            logger.log(.error, "Response parse failed: \(error)")
            return [errorEntry(account: account, type: "parse_error")]
        }
    }

    // MARK: - Token

    private func fetchOAuthToken() throws -> String {
        let process = Process()
        let pipe = Pipe()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/security")
        process.arguments = ["find-generic-password", "-s", keychainServiceName, "-w"]
        process.standardOutput = pipe
        process.standardError = FileHandle.nullDevice
        try process.run()

        // Read pipe BEFORE waitUntilExit to avoid deadlock when buffer > 64 KB
        let raw = pipe.fileHandleForReading.readDataToEndOfFile()

        // Timeout: kill the process if it hasn't exited within 10 seconds
        let deadline = DispatchTime.now() + .seconds(10)
        DispatchQueue.global().asyncAfter(deadline: deadline) { [weak process] in
            guard let p = process, p.isRunning else { return }
            p.terminate()
        }
        process.waitUntilExit()

        guard process.terminationStatus == 0 else {
            throw ConnectorError.keychainAccessDenied
        }
        guard let jsonString = String(data: raw, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines),
              !jsonString.isEmpty else {
            throw ConnectorError.keychainEmpty
        }

        guard let jsonData = jsonString.data(using: .utf8),
              let json = try JSONSerialization.jsonObject(with: jsonData) as? [String: Any],
              let oauthDict = json["claudeAiOauth"] as? [String: Any],
              let token = oauthDict["accessToken"] as? String,
              !token.isEmpty else {
            throw ConnectorError.tokenParseError
        }

        return token
    }

    // MARK: - Response parsing

    private struct ParsedUsage {
        let sessionPercent: Int
        let sessionResetAt: String
        let weeklyPercent: Int
        let weeklyResetAt: String
    }

    private func parseAPIResponse(_ data: Data) throws -> ParsedUsage {
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any],
              let fiveHour = json["five_hour"] as? [String: Any],
              let sevenDay = json["seven_day"] as? [String: Any],
              let sessionUtil = fiveHour["utilization"] as? Double,
              let sessionReset = fiveHour["resets_at"] as? String,
              let weeklyUtil = sevenDay["utilization"] as? Double,
              let weeklyReset = sevenDay["resets_at"] as? String else {
            throw ConnectorError.unexpectedAPIFormat
        }
        return ParsedUsage(
            sessionPercent: Int((sessionUtil * 100).rounded()),
            sessionResetAt: sessionReset,
            weeklyPercent: Int((weeklyUtil * 100).rounded()),
            weeklyResetAt: weeklyReset
        )
    }

    // MARK: - Helpers

    private func errorEntry(account: String, type: String) -> VendorUsageEntry {
        let now = ISO8601DateFormatter().string(from: Date())
        return VendorUsageEntry(
            vendor: vendor,
            account: account,
            isActive: true,
            lastAcquiredOn: nil,
            lastError: UsageError(timestamp: now, type: type),
            metrics: []
        )
    }
}

public enum ConnectorError: Error {
    case keychainAccessDenied
    case keychainEmpty
    case tokenParseError
    case unexpectedAPIFormat
}

