1	import Foundation
2	
3	public final class UsagesFileManager: Sendable {
4	    public let filePath: String
5	    public let lockPath: String
6	    private let logger: FileLogger
7	
8	    public init(
9	        filePath: String? = nil,
10	        logger: FileLogger = Loggers.app
11	    ) {
12	        let home = FileManager.default.homeDirectoryForCurrentUser.path
13	        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
14	        self.lockPath = self.filePath + ".lock"
15	        self.logger = logger
16	
17	        let dir = (self.filePath as NSString).deletingLastPathComponent
18	        do {
19	            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
20	        } catch {
21	            logger.log(.error, "Failed to create directory \(dir): \(error)")
22	        }
23	    }
24	
25	    // MARK: - Public
26	
27	    public func read() -> UsagesFile {
28	        withFlockShared {
29	            readUnsafe()
30	        } ?? UsagesFile()
31	    }
32	
33	    public func update(with entries: [VendorUsageEntry]) {
34	        let success = withFlockExclusive {
35	            var file = readUnsafe()
36	            file = merge(existing: file, incoming: entries)
37	            writeUnsafe(file)
38	        }
39	        if !success {
40	            logger.log(.error, "update(with:) skipped — failed to acquire exclusive flock")
41	        }
42	    }
43	
44	    // MARK: - Merge logic
45	
46	    func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
47	        var usages = existing.usages
48	        for entry in incoming {
49	            if let idx = usages.firstIndex(where: { $0.vendor == entry.vendor && $0.account == entry.account }) {
50	                usages[idx] = entry
51	            } else {
52	                usages.append(entry)
53	            }
54	        }
55	        return UsagesFile(usages: usages)
56	    }
57	
58	    // MARK: - Unsafe (caller holds lock)
59	
60	    private func readUnsafe() -> UsagesFile {
61	        guard let data = FileManager.default.contents(atPath: filePath) else {
62	            return UsagesFile()
63	        }
64	        do {
65	            let decoder = JSONDecoder()
66	            return try decoder.decode(UsagesFile.self, from: data)
67	        } catch {
68	            logger.log(.error, "Failed to decode \(filePath): \(error)")
69	            return UsagesFile()
70	        }
71	    }
72	
73	    private func writeUnsafe(_ file: UsagesFile) {
74	        let encoder = JSONEncoder()
75	        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
76	        guard let data = try? encoder.encode(file) else {
77	            logger.log(.error, "Failed to encode usages file")
78	            return
79	        }
80	        do {
81	            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
82	        } catch {
83	            logger.log(.error, "Atomic write failed: \(error)")
84	        }
85	        logger.log(.debug, "Wrote usages file to \(filePath)")
86	    }
87	
88	    // MARK: - POSIX flock
89	
90	    private func withFlockShared<T>(_ body: () -> T) -> T? {
91	        withFlock(operation: LOCK_SH, body)
92	    }
93	
